hudson.tasks.Shell.command:
#!/bin/bash set -euo pipefail
cd /workspace
REPO_DIR="__REPO_DIR__" REPO_OWNER="__REPO_OWNER__" TARGET_ENV="__TARGET_ENV__" TARGET_BRANCH="__TARGET_BRANCH__" TARGET_SERVICE="__TARGET_SERVICE__" SERVICE_PORT="__SERVICE_PORT__" HAS_COMPOSE_SERVICE="__HAS_COMPOSE_SERVICE__" COMMON_REPO="STS-Common" COMMON_BRANCH="MASTER-MOCK" COMPOSE_FILES="-f docker-compose.yml" COMPOSE_PROJECT_NAME="mock-sts" STATE_DIR="/var/jenkins_home/service-state" STATE_FILE="${STATE_DIR}/${REPO_DIR}-${TARGET_ENV}.sha" REPO_LOCK_ROOT="/var/jenkins_home/repo-locks" REPO_LOCK_DIR=""
compose() { docker-compose -p "${COMPOSE_PROJECT_NAME}" ${COMPOSE_FILES} "$@" }
needs_repo_lock() { case "${ACTION}" in auto|sync|ci|start) return 0 ;; *) return 1 ;; esac }
acquire_repo_lock() { mkdir -p "${REPO_LOCK_ROOT}" REPO_LOCK_DIR="${REPO_LOCK_ROOT}/${REPO_DIR}.lock" while ! mkdir "${REPO_LOCK_DIR}" 2>/dev/null; do echo "Waiting for repository lock: ${REPO_DIR}" sleep 1 done }
release_repo_lock() { if [ -n "${REPO_LOCK_DIR}" ] && [ -d "${REPO_LOCK_DIR}" ]; then rmdir "${REPO_LOCK_DIR}" 2>/dev/null || : fi }
ensure_repo() { if [ -d "${REPO_DIR}/.git" ]; then if ! git -C "${REPO_DIR}" ls-remote --exit-code --heads origin "${TARGET_BRANCH}" >/dev/null 2>&1; then echo "WARN: Branch ${TARGET_BRANCH} not found on origin for ${REPO_DIR}; skipping." return 10 fi
git -C "${REPO_DIR}" fetch origin "${TARGET_BRANCH}" git -C "${REPO_DIR}" checkout -B "${TARGET_BRANCH}" "origin/${TARGET_BRANCH}" return fi
if [ -d "${REPO_DIR}" ] && [ -n "$(ls -A "${REPO_DIR}" 2>/dev/null)" ]; then echo "ERROR: ${REPO_DIR} exists but is not a git repository." exit 1 fi
if [ -d "${REPO_DIR}" ]; then rmdir "${REPO_DIR}" fi
if [ -z "${GITHUB_TOKEN:-}" ] || [ "${GITHUB_TOKEN}" = "your_token_here" ]; then echo "ERROR: GITHUB_TOKEN is missing. Set it in compose env/.env." exit 1 fi
REMOTE_URL="https://${GITHUB_TOKEN}@github.com/${REPO_OWNER}/${REPO_DIR}.git" if ! git ls-remote --exit-code --heads "${REMOTE_URL}" "${TARGET_BRANCH}" >/dev/null 2>&1; then echo "WARN: Branch ${TARGET_BRANCH} not found on origin for ${REPO_DIR}; skipping." return 10 fi
git clone --branch "${TARGET_BRANCH}" --single-branch "${REMOTE_URL}" "${REPO_DIR}" }
service_not_mapped_message() { echo "No compose service mapping for ${REPO_DIR} (${TARGET_ENV}) in this repository." }
current_commit() { if [ ! -d "${REPO_DIR}/.git" ]; then echo "unknown" return 0 fi git -C "${REPO_DIR}" rev-parse HEAD }
deploy_target() { compose up -d --build --no-deps ${TARGET_SERVICE} compose ps ${TARGET_SERVICE}
# Register service in Nginx upstream local nginx_upstream_dir="/workspace/nginx/upstream.d" local upstream_file="${nginx_upstream_dir}/${REPO_DIR}-${TARGET_ENV}.conf" local service_host="${REPO_DIR}-${TARGET_ENV}" local upstream_port="${SERVICE_PORT:-80}"
mkdir -p "${nginx_upstream_dir}" cat > "${upstream_file}" << NGINXEOF # Auto-generated by Jenkins job ${REPO_DIR}-${TARGET_ENV} # Do not edit manually — will be overwritten on next deploy upstream ${service_host} { server ${service_host}:${upstream_port}; }
server { listen 80; server_name ${service_host}.sts.local ${RPO_DIR}-${TARGET_ENV};
location / { proxy_pass http://${service_host}; proxy_http_version 1.1; proxy_set_header Upgrade \$http_upgrade; proxy_set_header Connection "upgrade"; proxy_set_header Host \$host; proxy_set_header X-Real-IP \$remote_addr; proxy_set_header X-Forwarded-For \$proxy_add_x_forwarded_for; proxy_set_header X-Forwarded-Proto \$scheme; } } NGINXEOF
# Reload Nginx to pick up new config docker exec nginx_gateway nginx -s reload 2>/dev/null || true echo "Nginx upstream registered: ${service_host}:${upstream_port}" }
ensure_repo_for_action() { local rc if ensure_repo; then return 0 fi
rc=$? if [ "${rc}" -eq 10 ]; then echo "Branch ${TARGET_BRANCH} not found for ${REPO_DIR}; skip." exit 0 fi
return "${rc}" }
if needs_repo_lock; then acquire_repo_lock trap release_repo_lock EXIT fi
# ============================================ # Clone STS-Common (shared library) first # ============================================ ensure_common_repo() { local repo_dir="${COMMON_REPO}" local repo_owner="TomPhongphath" local branch="${COMMON_BRANCH}"
if [ -d "${repo_dir}/.git" ]; then git -C "${repo_dir}" fetch origin "${branch}" 2>/dev/null || return 0 git -C "${repo_dir}" checkout -B "${branch}" "origin/${branch}" 2>/dev/null || return 0 echo "STS-Common synced to $(git -C ${repo_dir} rev-parse --short HEAD)" return 0 fi
if [ -d "${repo_dir}" ] && [ -n "$(ls -A "${repo_dir}" 2>/dev/null)" ]; then echo "WARN: ${repo_dir} exists but is not a git repo; skipping common clone." return 0 fi
if [ -d "${repo_dir}" ]; then rmdir "${repo_dir}" 2>/dev/null fi
if [ -z "${GITHUB_TOKEN:-}" ] || [ "${GITHUB_TOKEN}" = "your_token_here" ]; then echo "WARN: GITHUB_TOKEN missing; cannot clone ${COMMON_REPO}." return 0 fi
local remote_url="https://${GITHUB_TOKEN}@github.com/${repo_owner}/${repo_dir}.git" if ! git ls-remote --exit-code --heads "${remote_url}" "${branch}" >/dev/null 2>&1; then echo "WARN: Branch ${branch} not found for ${COMMON_REPO}; skipping." return 0 fi
git clone --branch "${branch}" --single-branch "${remote_url}" "${repo_dir}" echo "Cloned ${COMMON_REPO} (${branch}) as shared dependency." }
case "${ACTION}" in auto) ensure_common_repo ensure_repo_for_action mkdir -p "${STATE_DIR}" COMMIT="$(current_commit)" if [ -f "${STATE_FILE}" ] && [ "$(cat "${STATE_FILE}")" = "${COMMIT}" ]; then echo "No new commit for ${REPO_DIR} (${TARGET_ENV}); skip deploy." exit 0 fi
if [ "${HAS_COMPOSE_SERVICE}" = "true" ]; then deploy_target echo "${COMMIT}" > "${STATE_FILE}" echo "Auto deploy complete for ${REPO_DIR} (${TARGET_ENV}) at ${COMMIT}." else service_not_mapped_message echo "${COMMIT}" > "${STATE_FILE}" fi ;; sync) ensure_common_repo ensure_repo_for_action echo "Source sync complete for ${REPO_DIR}." ;; ci) ensure_common_repo ensure_repo_for_action if [ "${HAS_COMPOSE_SERVICE}" = "true" ]; then compose build ${TARGET_SERVICE} echo "CI build complete for ${REPO_DIR} (${TARGET_ENV})." else service_not_mapped_message fi ;; start) ensure_common_repo ensure_repo_for_action if [ "${HAS_COMPOSE_SERVICE}" = "true" ]; then deploy_target mkdir -p "${STATE_DIR}" current_commit > "${STATE_FILE}" else service_not_mapped_message fi ;; restart) if [ "${HAS_COMPOSE_SERVICE}" = "true" ]; then compose restart ${TARGET_SERVICE} compose ps ${TARGET_SERVICE} else service_not_mapped_message fi ;; stop) if [ "${HAS_COMPOSE_SERVICE}" = "true" ]; then compose stop ${TARGET_SERVICE} compose ps ${TARGET_SERVICE} else service_not_mapped_message fi ;; status) if [ "${HAS_COMPOSE_SERVICE}" = "true" ]; then compose ps ${TARGET_SERVICE} else service_not_mapped_message fi ;; logs) if [ "${HAS_COMPOSE_SERVICE}" = "true" ]; then compose logs --tail=80 ${TARGET_SERVICE} else service_not_mapped_message fi ;; *) echo "Unknown ACTION=${ACTION}" exit 1 ;; esac
